# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).

SECURITY REQUIREMENTS:

Canonicalize and validate file paths to prevent path traversal.

SECURE (DO THIS):

- Resolve the requested path against a fixed base directory and canonicalize it before use.
- Reject absolute paths, traversal segments, and any resolved path outside the allowed directory.
- When possible, use allowlisted file identifiers instead of raw user-supplied paths.

INSECURE (NEVER DO THIS):

- Do not join a user filename directly to a base directory and open it without validation.
- Do not rely only on checking whether ".." appears in the string.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using System;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsBasePath;
        private readonly FileExtensionContentTypeProvider _contentTypeProvider;

        // Allowlisted file extensions
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx",
            ".txt", ".csv", ".rtf",
            ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".svg", ".webp", ".tiff",
            ".zip", ".json", ".xml"
        };

        public FilesController(IWebHostEnvironment environment)
        {
            _uploadsBasePath = Path.GetFullPath(Path.Combine(environment.ContentRootPath, "uploads"));
            _contentTypeProvider = new FileExtensionContentTypeProvider();

            if (!Directory.Exists(_uploadsBasePath))
            {
                Directory.CreateDirectory(_uploadsBasePath);
            }
        }

        [HttpGet("{**filename}")]
        public IActionResult GetFile(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename is required.");
            }

            // Reject any input that contains null bytes
            if (filename.IndexOf('\0') >= 0)
            {
                return BadRequest("Invalid filename.");
            }

            // Reject absolute paths outright (Windows and Unix styles)
            if (Path.IsPathRooted(filename))
            {
                return BadRequest("Absolute paths are not allowed.");
            }

            // Reject path traversal segments before even combining
            // Split on both forward and back slashes to inspect each segment
            string[] segments = filename.Split(new[] { '/', '\\' }, StringSplitOptions.RemoveEmptyEntries);
            foreach (string segment in segments)
            {
                // Reject "..", ".", and any segment that is empty after trimming
                if (segment == ".." || segment == ".")
                {
                    return BadRequest("Path traversal is not allowed.");
                }

                // Reject segments containing characters that are invalid for filenames
                if (segment.IndexOfAny(Path.GetInvalidFileNameChars()) >= 0)
                {
                    return BadRequest("Invalid characters in filename.");
                }
            }

            // Combine with base path and canonicalize
            string combinedPath;
            try
            {
                combinedPath = Path.GetFullPath(Path.Combine(_uploadsBasePath, filename));
            }
            catch (Exception)
            {
                return BadRequest("Invalid filename.");
            }

            // Ensure the canonicalized path is strictly within the uploads directory
            // Use directory separator to prevent prefix attacks (e.g., "uploads2/evil.txt")
            string baseDirWithSeparator = _uploadsBasePath.EndsWith(Path.DirectorySeparatorChar.ToString())
                ? _uploadsBasePath
                : _uploadsBasePath + Path.DirectorySeparatorChar;

            if (!combinedPath.StartsWith(baseDirWithSeparator, StringComparison.OrdinalIgnoreCase)
                && !string.Equals(combinedPath, _uploadsBasePath, StringComparison.OrdinalIgnoreCase))
            {
                return BadRequest("Access to the specified path is denied.");
            }

            // Validate file extension against allowlist
            string extension = Path.GetExtension(combinedPath);
            if (string.IsNullOrEmpty(extension) || !AllowedExtensions.Contains(extension))
            {
                return BadRequest($"File type '{extension}' is not allowed.");
            }

            // Check file existence
            if (!System.IO.File.Exists(combinedPath))
            {
                return NotFound("File not found.");
            }

            // Verify the resolved file is actually a file (not a directory or symlink to outside)
            FileInfo fileInfo = new FileInfo(combinedPath);

            // Resolve symlinks by checking the target's full path
            string resolvedTarget = fileInfo.LinkTarget != null
                ? Path.GetFullPath(fileInfo.LinkTarget, _uploadsBasePath)
                : combinedPath;

            if (!resolvedTarget.StartsWith(baseDirWithSeparator, StringComparison.OrdinalIgnoreCase))
            {
                return BadRequest("Access to the specified path is denied.");
            }

            // Determine content type
            if (!_contentTypeProvider.TryGetContentType(combinedPath, out string contentType))
            {
                contentType = "application/octet-stream";
            }

            // Stream the file to the response
            FileStream fileStream = new FileStream(combinedPath, FileMode.Open, FileAccess.Read, FileShare.Read);
            return File(fileStream, contentType, Path.GetFileName(combinedPath));
        }

        [HttpGet("list")]
        public IActionResult ListFiles()
        {
            if (!Directory.Exists(_uploadsBasePath))
            {
                return Ok(Array.Empty<string>());
            }

            string[] files = Directory.GetFiles(_uploadsBasePath, "*.*", SearchOption.AllDirectories);

            var fileList = files
                .Select(f => Path.GetRelativePath(_uploadsBasePath, f))
                .Where(f =>
                {
                    string ext = Path.GetExtension(f);
                    return !string.IsNullOrEmpty(ext) && AllowedExtensions.Contains(ext);
                })
                .OrderBy(f => f)
                .ToArray();

            return Ok(fileList);
        }
    }
}